class Solution:
    def nearestPalindromic(self, n):
        num = int(n)
        def is_pal(x):
            s = str(x)
            return s == s[::-1]
        lo = num - 1
        hi = num + 1
        while True:
            if lo >= 0 and is_pal(lo):
                low_ok = lo
            else:
                low_ok = None
            if is_pal(hi):
                high_ok = hi
            else:
                high_ok = None
            if low_ok is not None and high_ok is not None:
                if num - low_ok <= high_ok - num:
                    return str(low_ok)
                return str(high_ok)
            if low_ok is not None:
                return str(low_ok)
            if high_ok is not None:
                return str(high_ok)
            lo -= 1
            hi += 1

