class Solution:
    def nearestPalindromic(self, n):
        L = len(n)
        num = int(n)
        candidates = set()
        candidates.add(10 ** (L - 1) - 1)
        candidates.add(10 ** L + 1)
        prefix = int(n[:(L + 1) // 2])
        for p in (prefix - 1, prefix, prefix + 1):
            ps = str(p)
            if L % 2 == 0:
                cand = ps + ps[::-1]
            else:
                cand = ps + ps[:-1][::-1]
            candidates.add(int(cand))
        candidates.discard(num)
        best = None
        for c in candidates:
            if c < 0:
                continue
            if best is None:
                best = c
            else:
                dc = abs(c - num)
                db = abs(best - num)
                if dc < db or (dc == db and c < best):
                    best = c
        return str(best)

