var nearestPalindromic = function(n) {
    const L = n.length;
    const num = BigInt(n);
    const cands = new Set();
    cands.add(10n ** BigInt(L - 1) - 1n);
    cands.add(10n ** BigInt(L) + 1n);
    const prefix = BigInt(n.slice(0, (L + 1) >> 1));
    for (const p of [prefix - 1n, prefix, prefix + 1n]) {
        let ps = p.toString();
        let cand;
        if (L % 2 === 0) {
            cand = ps + ps.split('').reverse().join('');
        } else {
            cand = ps + ps.slice(0, -1).split('').reverse().join('');
        }
        cands.add(BigInt(cand));
    }
    cands.delete(num);
    let best = null;
    for (const c of cands) {
        if (c < 0n) continue;
        if (best === null) { best = c; continue; }
        const dc = c > num ? c - num : num - c;
        const db = best > num ? best - num : num - best;
        if (dc < db || (dc === db && c < best)) best = c;
    }
    return best.toString();
};
